import React from 'react'
import { CModal, CModalHeader, CModalBody } from '@coreui/react'
import PropTypes from 'prop-types'
import logo from 'src/assets/brand/logo.png'
import signature from 'src/assets/brand/signature.png'
import { getUser } from './Auth'

const Receipt = ({ visible, onClose, amount, rrr, date, desc }) => {
  const user = getUser()
  return (
    <>
      <CModal fullscreen visible={visible} onClose={onClose}>
        <CModalHeader></CModalHeader>
        <CModalBody>
          <div className="border p-4">
            <div className="d-block">
              <img src={logo} style={{ height: 'auto', width: '30%' }} />
            </div>
            <div className="border border-dark mt-2 border-3 text-center font-monospace p-1">
              <b>PAYMENT RECEIPT</b>
            </div>
            <div>
              <div className="row mt-3">
                <div className="col-9 font-monospace pl-4">
                  <label className="d-block fw-bold">
                    Student Name: {user.surname} {user.firstname}
                  </label>
                  <label className="d-block fw-bold">Deposit Amount: ₦{amount}</label>
                  <label className="d-block fw-bold">Receipt No: {rrr}</label>
                  <label className="d-block fw-bold">Date of Deposit: {date}</label>
                  <label className="d-block fw-bold">Payment Mode: Remita</label>
                </div>
              </div>

              <div className="table-responsive mt-2">
                <table className="table table-bordered border-2 border border-dark">
                  <thead>
                    <tr>
                      <th>S/N</th>
                      <th>Payment Description</th>
                      <th>Amount</th>
                    </tr>
                  </thead>
                  <tbody>
                    <tr>
                      <td>1</td>
                      <td>Transcript Payment ({desc})</td>
                      <td>{amount}</td>
                    </tr>
                  </tbody>
                </table>
              </div>
              <div className="row">
                <div className="col text-center">
                  <picture>
                    <img src={signature} className={{ height: 'auto', width: '30%' }} />
                  </picture>
                </div>
              </div>
            </div>
          </div>
        </CModalBody>
      </CModal>
    </>
  )
}

Receipt.propTypes = {
  visible: PropTypes.bool,
  onClose: PropTypes.any,
  amount: PropTypes.any,
  rrr: PropTypes.any,
  date: PropTypes.any,
  desc: PropTypes.string,
}

export default Receipt
